mapper.select:
SELECT rc.id, rc.contract_no, rc.title, rc.house_id, rc.landlord_id, rc.tenant_user_id, rc.house_order_info_id, rc.start_date, rc.end_date, rc.monthly_rent, rc.deposit_method_id, rc.deposit_amount, rc.pay_cycle, rc.utility_payment_mode, rc.contract_content, rc.attachment_url, rc.status, rc.reject_reason, rc.cancel_reason, rc.termination_reason, rc.termination_apply_user_id, rc.termination_refund_amount, rc.termination_voucher_url, rc.termination_voucher_note, rc.termination_audit_note, rc.termination_refund_voucher_url, rc.termination_refund_voucher_note, rc.confirm_time, rc.termination_apply_time, rc.termination_audit_time, rc.termination_refund_time, rc.create_time, rc.update_time, h.name AS house_name, h.cover AS house_cover, lu.username AS landlord_name, tu.username AS tenant_name FROM rental_contract rc LEFT JOIN house h ON h.id = rc.house_id LEFT JOIN landlord l ON l.id = rc.landlord_id LEFT JOIN user lu ON lu.id = l.user_id LEFT JOIN user tu ON tu.id = rc.tenant_user_id
AND ( rc.contract_no LIKE concat('%',#{keyword},'%') OR rc.title LIKE concat('%',#{keyword},'%') OR h.name LIKE concat('%',#{keyword},'%') OR tu.username LIKE concat('%',#{keyword},'%') )
AND rc.landlord_id = #{landlordId}
AND rc.tenant_user_id = #{tenantUserId}
AND rc.house_id = #{houseId}
AND rc.house_order_info_id = #{houseOrderInfoId}
AND rc.status = #{status}
AND rc.status NOT IN (1, 5)
ORDER BY rc.id DESC
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM rental_contract rc
LEFT JOIN house h ON h.id = rc.house_id
LEFT JOIN user tu ON tu.id = rc.tenant_user_id


        AND (
            rc.contract_no LIKE concat('%',#{keyword},'%')
            OR rc.title LIKE concat('%',#{keyword},'%')
            OR h.name LIKE concat('%',#{keyword},'%')
            OR tu.username LIKE concat('%',#{keyword},'%')
        )


        AND rc.landlord_id = #{landlordId}


        AND rc.tenant_user_id = #{tenantUserId}


        AND rc.house_id = #{houseId}


        AND rc.house_order_info_id = #{houseOrderInfoId}


        AND rc.status = #{status}


        AND rc.status NOT IN (1, 5)

SELECT COUNT(*)
FROM rental_contract
WHERE house_id = #{houseId}
  AND status IN (1, 2, 3, 4, 9, 10, 11, 12)

    AND id != #{excludeId}

SELECT COUNT(*)
FROM rental_contract
WHERE house_order_info_id = #{houseOrderInfoId}
